/**
 * Vercel build: inject PUBLIC_API_BASE into web/js/runtime-config.js.
 * Use HTTPS origin only (no secrets). Example: https://your-api.railway.app
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const outFile = path.join(__dirname, "..", "web", "js", "runtime-config.js");

const raw = process.env.PUBLIC_API_BASE ?? "";
const base = String(raw).trim().replace(/\/$/, "");

const contents = `/**
 * Generated by scripts/vercel-build-web.mjs — do not edit by hand on deployed builds.
 * Recreate locally: PUBLIC_API_BASE= npm run vercel-build
 */
export const API_BASE = ${JSON.stringify(base)};
`;

fs.writeFileSync(outFile, contents, "utf8");
console.log("[vercel-build-web] wrote", outFile, "API_BASE =", JSON.stringify(base));
